import React, { useState } from "react";

// Dentes FDI - permanentes e decíduos
const FDI_PERMANENTES_SUP = [18, 17, 16, 15, 14, 13, 12, 11, 21, 22, 23, 24, 25, 26, 27, 28];
const FDI_PERMANENTES_INF = [48, 47, 46, 45, 44, 43, 42, 41, 31, 32, 33, 34, 35, 36, 37, 38];
const FDI_DECIDUOS_SUP = ["55", "54", "53", "52", "51", "61", "62", "63", "64", "65"];
const FDI_DECIDUOS_INF = ["85", "84", "83", "82", "81", "71", "72", "73", "74", "75"];

// Faces possíveis por dente
const FACES = [
  { key: "vestibular", label: "Vestibular" },
  { key: "palatina", label: "Palatina/Lingual" },
  { key: "distal", label: "Distal" },
  { key: "coroa", label: "Coroa/Oclusal" },
  { key: "mesial", label: "Mesial" }
];

// Cores de status
const STATUS_CORES = {
  aberto: "#fbbf24",      // Amarelo
  finalizado: "#22c55e",  // Verde
  anotacao: "#6366f1",    // Roxo
  "": "#fff"              // Sem status
};

// Texto da legenda
const STATUS_LABELS = {
  aberto: "Aberto",
  finalizado: "Finalizado",
  anotacao: "Anotação"
};

export default function OdontogramaGuiaOdonto() {
  const [aba, setAba] = useState("permanentes");
  // Estado: dente selecionado + face selecionada
  const [selecao, setSelecao] = useState(null); // { dente: "11", face: "coroa" }
  // Estado: tratamentos já marcados
  const [facesStatus, setFacesStatus] = useState({}); // { "11_coroa": "aberto", ... }

  // Troca status (ao clicar em face)
  function handleClickFace(dente, face) {
    setSelecao({ dente, face });
  }

  // Salva o tratamento para o dente/face selecionados
  function salvarTratamento(status) {
    if (!selecao) return;
    setFacesStatus(prev => ({
      ...prev,
      [`${selecao.dente}_${selecao.face}`]: status
    }));
    setSelecao(null);
  }

  // Limpa seleção atual
  function cancelarSelecao() {
    setSelecao(null);
  }

  // Dados dos dentes conforme aba
  const dentesSup = aba === "permanentes" ? FDI_PERMANENTES_SUP : FDI_DECIDUOS_SUP;
  const dentesInf = aba === "permanentes" ? FDI_PERMANENTES_INF : FDI_DECIDUOS_INF;

  // Layout responsivo
  return (
    <div className="w-full max-w-5xl mx-auto p-4 flex flex-col items-center">
      {/* Abas */}
      <div className="flex gap-4 mb-2">
        <button
          className={`px-4 py-1 rounded ${aba === "permanentes" ? "bg-blue-600 text-white" : "bg-gray-200 text-gray-700"}`}
          onClick={() => setAba("permanentes")}
        >
          Permanentes
        </button>
        <button
          className={`px-4 py-1 rounded ${aba === "deciduos" ? "bg-blue-600 text-white" : "bg-gray-200 text-gray-700"}`}
          onClick={() => setAba("deciduos")}
        >
          Decíduos
        </button>
      </div>

      {/* Painel de ação ao selecionar uma face */}
      {selecao && (
        <div className="w-full flex flex-col items-center mb-4 animate-fade-in">
          <div className="bg-white border shadow-sm rounded-xl p-3 flex flex-col sm:flex-row gap-4 items-center">
            <div className="text-sm font-semibold text-gray-700">
              Dente <span className="text-blue-600">{selecao.dente}</span> — Face <span className="text-blue-600">{FACES.find(f => f.key === selecao.face).label}</span>
            </div>
            <div className="flex gap-2">
              <button
                className="px-4 py-1 rounded bg-yellow-400 text-white font-semibold"
                onClick={() => salvarTratamento("aberto")}
              >
                Aberto
              </button>
              <button
                className="px-4 py-1 rounded bg-green-500 text-white font-semibold"
                onClick={() => salvarTratamento("finalizado")}
              >
                Finalizado
              </button>
              <button
                className="px-4 py-1 rounded bg-indigo-500 text-white font-semibold"
                onClick={() => salvarTratamento("anotacao")}
              >
                Anotação
              </button>
              <button
                className="px-4 py-1 rounded bg-gray-300 text-gray-700"
                onClick={cancelarSelecao}
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Quadrantes (Q1/Q2/Q3/Q4) */}
      <div className="w-full flex justify-between text-xs text-gray-400 mb-1 max-w-4xl">
        <span>Q2</span>
        <span>Q1</span>
        <span>Q4</span>
        <span>Q3</span>
      </div>

      {/* Odontograma visual */}
      <div className="w-full overflow-auto">
        {/* Dentes superiores */}
        <div className="flex justify-center items-end mb-1 gap-1">
          {dentesSup.map(dente => (
            <OdontoDente
              key={dente}
              dente={dente}
              selecao={selecao}
              onClickFace={handleClickFace}
              facesStatus={facesStatus}
              superior
            />
          ))}
        </div>
        {/* Numeração FDI superior */}
        <div className="flex justify-center gap-1 mb-2">
          {dentesSup.map(num => (
            <span key={num} className="block w-9 text-xs text-center text-gray-700 font-bold">{num}</span>
          ))}
        </div>
        {/* Dentes inferiores */}
        <div className="flex justify-center items-start mt-1 gap-1">
          {dentesInf.map(dente => (
            <OdontoDente
              key={dente}
              dente={dente}
              selecao={selecao}
              onClickFace={handleClickFace}
              facesStatus={facesStatus}
              superior={false}
            />
          ))}
        </div>
        {/* Numeração FDI inferior */}
        <div className="flex justify-center gap-1 mt-1">
          {dentesInf.map(num => (
            <span key={num} className="block w-9 text-xs text-center text-gray-700 font-bold">{num}</span>
          ))}
        </div>
      </div>

      {/* Legenda */}
      <div className="flex gap-4 justify-center mt-6 text-xs">
        <Legenda cor={STATUS_CORES.aberto} texto="Aberto" />
        <Legenda cor={STATUS_CORES.finalizado} texto="Finalizado" />
        <Legenda cor={STATUS_CORES.anotacao} texto="Anotação" />
      </div>
    </div>
  );
}

// Dente individual SVG, faces destacáveis
function OdontoDente({ dente, selecao, onClickFace, facesStatus, superior }) {
  // Ordem das faces para disposição SVG
  const faceOrder = ["vestibular", "mesial", "coroa", "distal", "palatina"];
  // Posição da face selecionada
  const selecaoKey = selecao && selecao.dente === String(dente) ? selecao.face : null;

  return (
    <svg
      viewBox="0 0 38 48"
      width="36"
      height="46"
      style={{ cursor: "pointer", userSelect: "none" }}
    >
      {/* Faces (divisão SVG simplificada) */}
      {/* Vestibular */}
      <polygon
        points="8,8 30,8 28,16 10,16"
        fill={getCor(facesStatus, dente, "vestibular", selecaoKey)}
        stroke={getStroke(facesStatus, dente, "vestibular", selecaoKey)}
        strokeWidth={selecaoKey === "vestibular" ? 3 : 1.3}
        onClick={() => onClickFace(String(dente), "vestibular")}
      />
      {/* Mesial */}
      <polygon
        points="8,8 10,16 16,24 16,14"
        fill={getCor(facesStatus, dente, "mesial", selecaoKey)}
        stroke={getStroke(facesStatus, dente, "mesial", selecaoKey)}
        strokeWidth={selecaoKey === "mesial" ? 3 : 1.3}
        onClick={() => onClickFace(String(dente), "mesial")}
      />
      {/* Coroa/Oclusal */}
      <polygon
        points="10,16 28,16 22,28 16,24"
        fill={getCor(facesStatus, dente, "coroa", selecaoKey)}
        stroke={getStroke(facesStatus, dente, "coroa", selecaoKey)}
        strokeWidth={selecaoKey === "coroa" ? 3 : 1.3}
        onClick={() => onClickFace(String(dente), "coroa")}
      />
      {/* Distal */}
      <polygon
        points="28,16 30,8 22,14 22,24"
        fill={getCor(facesStatus, dente, "distal", selecaoKey)}
        stroke={getStroke(facesStatus, dente, "distal", selecaoKey)}
        strokeWidth={selecaoKey === "distal" ? 3 : 1.3}
        onClick={() => onClickFace(String(dente), "distal")}
      />
      {/* Palatina/Lingual */}
      <polygon
        points="16,24 22,28 22,38 16,38"
        fill={getCor(facesStatus, dente, "palatina", selecaoKey)}
        stroke={getStroke(facesStatus, dente, "palatina", selecaoKey)}
        strokeWidth={selecaoKey === "palatina" ? 3 : 1.3}
        onClick={() => onClickFace(String(dente), "palatina")}
      />
      {/* Contorno do dente */}
      <rect
        x="8"
        y="8"
        width="20"
        height="30"
        fill="none"
        stroke="#bbb"
        strokeWidth={1.2}
        rx={8}
        ry={8}
        pointerEvents="none"
      />
    </svg>
  );
}

// Cor de cada face
function getCor(facesStatus, dente, face, selecaoKey) {
  const status = facesStatus[`${dente}_${face}`] || "";
  if (selecaoKey === face) return "#bae6fd";
  return STATUS_CORES[status] || "#fff";
}

// Borda da face
function getStroke(facesStatus, dente, face, selecaoKey) {
  if (selecaoKey === face) return "#2563eb";
  const status = facesStatus[`${dente}_${face}`] || "";
  return status ? "#2563eb" : "#bbb";
}

function Legenda({ cor, texto }) {
  return (
    <span className="flex items-center gap-1">
      <span
        style={{
          display: "inline-block",
          width: 18,
          height: 18,
          borderRadius: "50%",
          background: cor,
          border: "1.5px solid #333",
        }}
      />
      <span style={{ color: "#333" }}>{texto}</span>
    </span>
  );
}
